from django.http import HttpResponse


def demo_shell():
    return HttpResponse("""<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>AgentLand Chat</title><style>body{margin:0;background:#edf4e9;color:#17212b;font-family:ui-monospace,Consolas,monospace}main{max-width:920px;margin:auto;padding:28px 20px}.top{display:flex;justify-content:space-between;align-items:center;gap:12px}.tag{background:#17212b;color:#fff;padding:6px 9px;font-size:12px}.chat{max-width:720px;margin:28px auto}.bubble{background:#fff;border:3px solid #17212b;padding:18px;box-shadow:6px 6px #b6c5bd;margin:14px 0}.bubble.agent{background:#d9e8f5}.composer{display:flex;gap:8px;align-items:end}.composer textarea{flex:1;min-height:70px;resize:vertical}.composer textarea,input,select,button{font:inherit;padding:10px;border:2px solid #17212b}.composer textarea,select{width:100%;box-sizing:border-box}button{background:#d9e8f5;cursor:pointer}.row{display:flex;gap:8px;align-items:center;flex-wrap:wrap}.row label{flex:1;min-width:220px}.note{font-size:12px;color:#53616a}.error{color:#9b2424}.sessions{margin-top:26px}.session{border-top:1px solid #ccd6c8;padding:12px 0;font-size:13px}.session a{margin-right:12px}@media(max-width:600px){.composer{display:block}.composer button{margin-top:8px;width:100%}}</style></head><body><main><div class="top"><span class="tag">AGENTLAND</span><span class="note">A shared chat for auditable AI work</span></div><section class="chat"><div class="bubble agent"><strong>AgentLand</strong><p>What should we work on?</p><p class="note">Describe the mission in natural language. I’ll create a session and title it from your prompt.</p></div><div class="bubble"><label for="prompt"><strong>Your prompt</strong></label><div class="composer"><textarea id="prompt" placeholder="e.g. Repair room isolation and verify the fixed test...">Repair whiteboard room isolation</textarea><button id="send">Start session</button></div><div class="row"><label>Provider<select id="provider"><option value="deterministic">Deterministic Demo</option><option value="codex">Codex — unavailable in current environment</option></select></label><span id="provider-note" class="note">Demo provider validates the evidence pipeline.</span></div><p id="message" class="note"></p></div><div class="row"><button id="showcase">Run Evidence Demo</button><button id="reset">Reset Demo</button></div><section class="sessions"><h2>Recent chats</h2><div id="sessions">Loading…</div></section></section></main><script>const q=s=>document.querySelector(s),message=q('#message');const titleFor=prompt=>{const clean=prompt.replace(/\s+/g,' ').trim();return clean.length>64?clean.slice(0,61)+'…':clean||'AgentLand session'};function say(text,error=false){message.textContent=text;message.className=error?'error':'note'}q('#provider').onchange=()=>q('#provider-note').textContent=q('#provider').value==='codex'?'Codex requested with least privilege; this environment may block process launch.':'Demo provider validates the evidence pipeline.';async function load(){const response=await fetch('/agentland/sessions/'),data=await response.json(),box=q('#sessions');box.replaceChildren();if(!data.sessions.length){box.textContent='No chats yet.';return}data.sessions.forEach(session=>{const row=document.createElement('div');row.className='session';const title=document.createElement('strong');title.textContent=titleFor(session.mission);const meta=document.createElement('span');meta.textContent=' · '+session.status+' · '+session.current_sequence+' events';const city=document.createElement('a');city.href='/agentland/sessions/'+session.id+'/city/';city.textContent='Open chat';const start=document.createElement('button');start.textContent='Start run';start.onclick=()=>startRun(session.id,q('#provider').value);row.append(title,meta,document.createElement('br'),city,start);box.appendChild(row)})}async function create(){const prompt=q('#prompt').value.trim();if(!prompt){say('Write a prompt first.',true);return}say('Creating '+titleFor(prompt)+'…');const response=await fetch('/agentland/sessions/',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({mission:prompt})}),data=await response.json();if(!response.ok){say(data.error,true);return}location.href='/agentland/sessions/'+data.id+'/city/'}async function startRun(id,provider){say('Starting '+provider+'…');const response=await fetch('/agentland/sessions/'+id+'/dispatch-builder/',{method:'POST',headers:{'Content-Type':'application/json','Idempotency-Key':crypto.randomUUID()},body:JSON.stringify({runner_identity:provider})}),data=await response.json();if(!response.ok){say(data.error,true);return}location.href='/agentland/sessions/'+id+'/city/'}q('#send').onclick=create;q('#reset').onclick=async()=>{const response=await fetch('/agentland/reset-baseline/',{method:'POST'});say(response.ok?'Demo reset: broken baseline restored.':(await response.json()).error,!response.ok)};q('#showcase').onclick=async()=>{await fetch('/agentland/reset-baseline/',{method:'POST'});const response=await fetch('/agentland/sessions/',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({mission:'Repair whiteboard room isolation'})}),session=await response.json();if(!response.ok){say(session.error,true);return}location.href='/agentland/sessions/'+session.id+'/city/?autostart=deterministic'};load();</script></body></html>""")
